SourceCode.Declaration:
/// <summary>
/// Whitelist of allowed item substitutions for the Sales Proration Accelerator.
/// A row says: when FromItemId is short, ToItemId may be offered instead —
/// optionally only for one customer (CustAccount blank = all customers),
/// converted by QtyRatio, within ValidFrom/ValidTo.
/// </summary>
public class RSMItemSubstitution extends common
{
}

Method.Source:
/// <summary>Active rule for an exact (from, to, customer) triple; customer-specific wins over blank.</summary>
public static RSMItemSubstitution findActive(
    ItemId      _fromItemId,
    ItemId      _toItemId,
    CustAccount _custAccount = '',
    TransDate   _asOf        = systemDateGet())
{
    RSMItemSubstitution sub;

    select firstonly sub
        where sub.FromItemId  == _fromItemId
           && sub.ToItemId    == _toItemId
           && (sub.CustAccount == _custAccount || sub.CustAccount == '')
           && (!sub.ValidFrom || sub.ValidFrom <= _asOf)
           && (!sub.ValidTo   || sub.ValidTo   >= _asOf);

    return sub;
}

/// <summary>
/// All active substitutes for an item (ranked). Includes Bidirectional rows
/// where the item appears on the To side.
/// </summary>
public static List activeSubstitutesFor(
    ItemId      _itemId,
    CustAccount _custAccount = '',
    TransDate   _asOf        = systemDateGet())
{
    List                result = new List(Types::Record);
    RSMItemSubstitution sub;

    while select sub
        order by sub.Rank asc
        where (sub.FromItemId == _itemId
           || (sub.ToItemId   == _itemId && sub.Direction == RSMSubstitutionDirection::Bidirectional))
           && (sub.CustAccount == _custAccount || sub.CustAccount == '')
           && (!sub.ValidFrom || sub.ValidFrom <= _asOf)
           && (!sub.ValidTo   || sub.ValidTo   >= _asOf)
    {
        result.addEnd(sub);
    }
    return result;
}

public boolean validateWrite()
{
    boolean ok = super();

    if (this.FromItemId == this.ToItemId)
    {
        ok = checkFailed("@SYS9039"); // An item cannot substitute itself.
    }
    if (this.QtyRatio <= 0)
    {
        this.QtyRatio = 1.0;
    }
    if (this.ValidFrom && this.ValidTo && this.ValidFrom > this.ValidTo)
    {
        ok = checkFailed("@SYS72396"); // From date is after To date.
    }
    return ok;
}
